// ============================================
// 数据模型定义
// ============================================

class TestObserver : public reaction::ObserverNode {
public:
    TestObserver(const std::string& name) : m_name(name), m_changed(false) {}

    void valueChanged(bool changed = true) override {
        m_changed = changed;
        m_callCount++;
        // Call base class to propagate notification to observers
        ObserverNode::valueChanged(changed);
    }

    bool wasChanged() const { return m_changed; }
    int getCallCount() const { return m_callCount; }
    const std::string& getName() const { return m_name; }

private:
    std::string m_name;
    bool m_changed;
    int m_callCount = 0;
};

// ============================================
// 函数实现
// ============================================

/**
 * Function: Create observer relationship and test notification
 *
 * @param observerName Name for the observer node
 * @param targetName Name for the target node
 * @return std::pair<bool, int> Pair of whether observer was notified and call count
 */
std::pair<bool, int> test_observer_notification(const std::string& observerName, const std::string& targetName) {
    // 1. Create two TestObserver instances (observer and target)
    auto observer = std::make_shared<TestObserver>(observerName);
    auto target = std::make_shared<TestObserver>(targetName);

    // 2. Get the singleton ObserverGraph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Add the observer relationship (observer observes target)
    graph.addObserver(observer, target);

    // 4. Notify the target of a change
    target->notify(true);

    // 5. Check if the observer was notified and return the result
    return {observer->wasChanged(), observer->getCallCount()};
}

}  // namespace test_reaction
```

## Explanation:

1. **Creating Observers**: Two `TestObserver` instances are created using `std::make_shared` - one as the observer and one as the target.

2. **Getting Graph Instance**: The singleton `ObserverGraph` instance is retrieved using `reaction::ObserverGraph::getInstance()`.

3. **Adding Observer Relationship**: The `addObserver` method is called with the observer and target, establishing the relationship where the observer will be notified when the target changes.

4. **Notifying Target**: The target is notified of a change using `target->notify(true)`, which triggers the notification chain through the observer graph.

5. **Returning Results**: The function returns a pair containing:
   - Whether the observer was notified (`observer->wasChanged()`)
   - The call count of the observer's `valueChanged` method (`observer->getCallCount()`)

This implementation follows the reactive programming pattern where changes propagate through the observer graph, and the test verifies that notifications are correctly delivered between nodes.

