    boolVar.value(false); // Flip boolean
    intVar.value(3);     // Update integer

    // 7. Get updated values
    snapshot.updatedNegatedSum = negatedSum.get();
    snapshot.logicalNotAfterFlip = logicalNot.get();
    snapshot.bitwiseNotValue = bitwiseNot.get();

